mapper.insert:
/* com.educare.edu.comn.mapper.LectureDormiMapper.insertByPk */
	insert into t_lecture_dormi
	(dormi_nm	,place		,memo		,use_yn		, capa_cnt
	, access_yn
	, reg_id, reg_de, upd_id, upd_de)
	values 
	(#{dormiNm}	,#{place}	,#{memo}	,#{useYn}	,#{capaCnt}
	,#{accessYn}
	,#{regId},#{regDe},#{updId},#{updDe})

mapper.update:
/* com.educare.edu.comn.mapper.LectureDormiMapper.updateByPk */
	update t_lecture_dormi
	set 
	upd_id = #{updId}
	,upd_de = #{updDe}
	,dormi_nm = #{dormiNm}
	,access_yn = #{accessYn}
	,capa_cnt = #{capaCnt}
	,place = #{place}
	,memo = #{memo}
	,use_yn = #{useYn}
	where dormi_seq = #{dormiSeq}

mapper.select:
/* com.educare.edu.comn.mapper.LectureDormiMapper.selectByParam */
	SELECT * FROM t_lecture_dormi
	WHERE 1=1 

	and DORMI_SEQ = #{dormiSeq} 


	and USE_YN = #{useYn} 

	order by dormi_nm

/* com.educare.edu.comn.mapper.LectureDormiMapper.selectPageList */
	SELECT * FROM t_lecture_dormi
	WHERE 1=1 

	order by dormi_seq desc
	limit #{firstIndex} , #{rowCnt}

/* com.educare.edu.comn.mapper.LectureDormiMapper.getLectureDormiListForPeriod */ /** 특정기간 빈방 목록 */ SELECT d.dormi_seq, d.dormi_nm, d.capa_cnt, d.place, d.access_yn, COALESCE(s.assigned_cnt, 0) AS assigned_cnt FROM t_lecture_dormi d LEFT JOIN ( SELECT dormi_seq, COUNT(*) AS assigned_cnt FROM t_lecture_dormi_stdnt WHERE NOT (end_dt <=#{srchStartDt} OR start_dt >= #{srchEndDt}) GROUP BY dormi_seq ) s ON d.dormi_seq = s.dormi_seq WHERE d.use_yn = 'Y'
AND COALESCE(s.assigned_cnt, 0) < d.capa_cnt
and d.dormi_seq = #{srchDormiSeq}
and d.dormi_seq in
#{item}
ORDER BY d.dormi_seq FOR UPDATE of d

/* com.educare.edu.comn.mapper.LectureDormiMapper.selectLectureStdntListForAssign */ /** 특정수업의 학생명단, 배정정보 포함 */ select a.edu_seq, a.user_id, a.dormi_fee, a.meal_fee, a.deposit_yn , b.start_dt, b.end_dt, b.dormi_seq , (select dormi_nm from t_lecture_dormi where dormi_seq = b.dormi_seq) dormi_nm , (select capa_cnt from t_lecture_dormi where dormi_seq = b.dormi_seq) capa_cnt , (select access_yn from t_lecture_dormi where dormi_seq = b.dormi_seq) access_yn , (select dormi_access_yn from t_lecture_rcept where rcept_seq = a.rcept_seq) rcept_access_yn , (select dormi_capa_cnt from t_lecture_rcept where rcept_seq = a.rcept_seq) rcept_capa_cnt , (select use_trans from t_lecture_rcept where rcept_seq = a.rcept_seq) use_trans from t_lecture_stdnt a left join ( select * from t_lecture_dormi_stdnt where not (end_dt <#{srchStartDt} OR start_dt > #{srchEndDt}) ) b on a.user_id = b.user_id and a.edu_seq = b.edu_seq where a.edu_seq = #{eduSeq} and a.state in (2, 4)
and a.user_id = #{srchUserId}
limit #{firstIndex}, #{rowCnt}

/* com.educare.edu.comn.mapper.LectureDormiMapper.selectLectureStdntPageCnt */
	/** 숙소배정 전체수, 페이징처리 */
	select count(a.edu_seq)
	from t_lecture_stdnt a
	where a.edu_seq = #{eduSeq} and a.state in (2,4)

/* com.educare.edu.comn.mapper.LectureDormiMapper.getAssignLectureDormi */ /** 숙소 사용현황 */ select a.edu_seq,a.user_id,a.start_dt,a.end_dt,a.dormi_seq ,b.dormi_nm from t_lecture_dormi_stdnt a inner join t_lecture_dormi b on a.dormi_seq = b.dormi_seq where a.dormi_seq > 0
and #{srchDt} between a.start_dt and a.end_dt
and b.dormi_seq = #{dormiSeq}
and not ( a.end_dt < concat(#{srchYear},'-',#{srchMonth},'-01') or a.start_dt > concat(#{srchYear},'-',#{srchMonth},'-31') )
